/**
 * Get the verse of the day based on day-of-year (deterministic, not random).
 */
export function getVerseOfTheDay(): Verse {
  const now = new Date();
  const start = new Date(now.getFullYear(), 0, 0);
  const diff = now.getTime() - start.getTime();
  const oneDay = 1000 * 60 * 60 * 24;
  const dayOfYear = Math.floor(diff / oneDay);
  const index = (dayOfYear - 1) % DAILY_VERSES_KJV.length; // day 1 = index 0
  return DAILY_VERSES_KJV[Math.max(0, index)];
}

/**
 * Get a verse by specific day-of-year index (1-365).
 */
export function getVerseForDay(dayOfYear: number): Verse {
  const index = ((dayOfYear - 1) % DAILY_VERSES_KJV.length + DAILY_VERSES_KJV.length) % DAILY_VERSES_KJV.length;
  return DAILY_VERSES_KJV[index];
}

/**
 * Format a verse reference string.
 */
export function formatVerseRef(verse: Verse): string {
  return `${verse.book} ${verse.chapter}:${verse.verse}`;
}

/**
 * Format a verse for sharing.
 */
export function formatVerseForSharing(verse: Verse): string {
  const ref = formatVerseRef(verse);
  return `\u201C${verse.text}\u201D\n\n\u2014 ${ref} (${verse.translation})\n\nShared via Scripture Streak`;
}
